#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define BUCKET_CAPACITY 2
#define INITIAL_DEPTH 1

// Bucket structure
typedef struct Bucket {
 int local_depth;
 int count;
 int keys[BUCKET_CAPACITY];
} Bucket;

// Directory structure
typedef struct Directory {
 int global_depth;
 int size; // 2^global_depth
 Bucket **buckets;
} Directory;

// Create a new bucket
Bucket* createBucket(int local_depth) {
 Bucket *bucket = (Bucket*)malloc(sizeof(Bucket));
 bucket->local_depth = local_depth;
 bucket->count = 0;
 for (int i = 0; i < BUCKET_CAPACITY; i++) {
 bucket->keys[i] = -1; // -1 indicates empty slot
 }
 return bucket;
}

// Create and initialize directory
Directory* createDirectory() {
 Directory *dir = (Directory*)malloc(sizeof(Directory));
 dir->global_depth = INITIAL_DEPTH;
 dir->size = 1 << INITIAL_DEPTH; // 2^depth
 dir->buckets = (Bucket**)malloc(dir->size * sizeof(Bucket*));

 // Initialize with empty buckets
 for (int i = 0; i < dir->size; i++) {
 dir->buckets[i] = createBucket(INITIAL_DEPTH);
 }
 return dir;
}

// Hash function - returns 32-bit hash value
int hashFunction(int key) {
 // Simple hash using modulo and bit manipulation
 return ((key * 2654435761) & 0x7FFFFFFF);
}

// Get directory index using leading 'depth' bits
int getIndex(int hash_value, int depth) {
 int mask = (1 << depth) - 1;
 return hash_value & mask;
}

// Double the directory size
void doubleDirectory(Directory *dir) {
 int old_size = dir->size;
 dir->size *= 2;
 dir->global_depth++;

 // Reallocate bucket pointer array
 Bucket **new_buckets = (Bucket**)malloc(dir->size * sizeof(Bucket*));

 // Duplicate pointers: each old entry maps to two new entries
 for (int i = 0; i < old_size; i++) {
 new_buckets[2 * i] = dir->buckets[i];
 new_buckets[2 * i + 1] = dir->buckets[i];
 }

 free(dir->buckets);
 dir->buckets = new_buckets;

 printf("Directory doubled. New size: %d, Global depth: %d\n", 
 dir->size, dir->global_depth);
}

// Split bucket and redistribute records
void splitBucket(Directory *dir, int bucket_index) {
 Bucket *old_bucket = dir->buckets[bucket_index];

 // If local depth equals global depth, double directory first
 if (old_bucket->local_depth == dir->global_depth) {
 doubleDirectory(dir);
 // After doubling, recalculate the index
 // The old bucket's records will determine new index
 }

 // Create two new buckets
 Bucket *bucket1 = createBucket(old_bucket->local_depth + 1);
 Bucket *bucket2 = createBucket(old_bucket->local_depth + 1);

 // Redistribute existing records
 for (int i = 0; i < old_bucket->count; i++) {
 int key = old_bucket->keys[i];
 int hash_val = hashFunction(key);
 int bit_pos = old_bucket->local_depth; // Use next bit for redistribution

 // Check the bit at position (31 - bit_pos)
 if ((hash_val >> (31 - bit_pos)) & 1) {
 // Bit is 1 - goes to bucket2
 bucket2->keys[bucket2->count++] = key;
 } else {
 // Bit is 0 - goes to bucket1
 bucket1->keys[bucket1->count++] = key;
 }
 }

 // Update directory pointers
 int mask = (1 << (dir->global_depth - old_bucket->local_depth)) - 1;
 int base = bucket_index & ~mask;

 // Clear local depth bits to get base index
 for (int i = 0; i < dir->size; i++) {
 if (dir->buckets[i] == old_bucket) {
 // Calculate which new bucket this index should point to
 int index_in_group = (i - base) >> (dir->global_depth - old_bucket->local_depth - 1);
 if (index_in_group % 2 == 0) {
 dir->buckets[i] = bucket1;
 } else {
 dir->buckets[i] = bucket2;
 }
 }
 }

 // Update local depths
 bucket1->local_depth = old_bucket->local_depth + 1;
 bucket2->local_depth = old_bucket->local_depth + 1;

 free(old_bucket);
 printf("Bucket split. New local depth: %d\n", bucket1->local_depth);
}

// Insert a key into the directory
void insert(Directory *dir, int key) {
 int hash_val = hashFunction(key);
 int index = getIndex(hash_val, dir->global_depth);
 Bucket *bucket = dir->buckets[index];

 // Check if bucket has space
 if (bucket->count < BUCKET_CAPACITY) {
 bucket->keys[bucket->count++] = key;
 printf("Inserted %d at index %d\n", key, index);
 return;
 }

 // Bucket is full - need to split
 printf("Bucket at index %d is full. Splitting...\n", index);
 splitBucket(dir, index);

 // Retry insertion after split
 insert(dir, key);
}

// Search for a key
int search(Directory *dir, int key) {
 int hash_val = hashFunction(key);
 int index = getIndex(hash_val, dir->global_depth);
 Bucket *bucket = dir->buckets[index];

 for (int i = 0; i < bucket->count; i++) {
 if (bucket->keys[i] == key) {
 return 1; // Found
 }
 }
 return 0; // Not found
}

// Display directory state
void display(Directory *dir) {
 printf("\n=== Extendible Hash Table ===\n");
 printf("Global Depth: %d\n", dir->global_depth);
 printf("Directory Size: %d\n", dir->size);
 printf("\nDirectory and Buckets:\n");

 for (int i = 0; i < dir->size; i++) {
 Bucket *bucket = dir->buckets[i];
 printf(" [%d] (depth=%d): ", i, dir->global_depth);
 printf("Bucket(local_depth=%d): [", bucket->local_depth);
 for (int j = 0; j < bucket->count; j++) {
 printf("%d", bucket->keys[j]);
 if (j < bucket->count - 1) printf(", ");
 }
 printf("]\n");
 }
}

// Free all memory
void freeDirectory(Directory *dir) {
 // Only free unique buckets (pointers that aren't duplicated)
 int *is_freed = (int*)calloc(dir->size, sizeof(int));

 for (int i = 0; i < dir->size; i++) {
 if (!is_freed[i]) {
 free(dir->buckets[i]);
 is_freed[i] = 1;
 }
 }
 free(is_freed);
 free(dir->buckets);
 free(dir);
}

// Main function demonstrating the algorithm
int main() {
 Directory *dir = createDirectory();

 printf("=== Inserting Keys ===\n");
 int keys[] = {4, 10, 22, 15, 5, 31};
 int num_keys = sizeof(keys) / sizeof(keys[0]);

 for (int i = 0; i < num_keys; i++) {
 insert(dir, keys[i]);
 display(dir);
 }

 printf("\n=== Searching ===\n");
 printf("Search for 15: %s\n", search(dir, 15) ? "Found" : "Not Found");
 printf("Search for 100: %s\n", search(dir, 100) ? "Found" : "Not Found");

 freeDirectory(dir);
 return 0;
}
